-- Private audit bridge: executable by controlled SECURITY DEFINER functions only, never by clients.
create or replace function public.append_reporting_audit_event(p_t uuid,p_o uuid,p_f uuid,p_action text,p_entity_type text,p_entity_id uuid,p_metadata jsonb default '{}'::jsonb) returns uuid language plpgsql security definer set search_path=public as $$ declare id uuid; begin if current_setting('app.reporting_audit',true)<>'on' or auth.uid() is null or p_metadata ?| array['password','token','secret','access_token'] then raise exception 'Reporting audit event is not authorized'; end if; insert into public.audit_events(tenant_id,organization_id,facility_id,actor_id,action,entity_type,entity_id,metadata) values(p_t,p_o,p_f,auth.uid(),p_action,p_entity_type,p_entity_id,p_metadata) returning id into id; return id; end $$;
create or replace function public.publish_report_version(p_definition_id uuid,p_version_id uuid) returns void language plpgsql security definer set search_path=public as $$ declare d public.report_definitions%rowtype; v public.report_versions%rowtype; begin select * into d from public.report_definitions where id=p_definition_id for update; select * into v from public.report_versions where id=p_version_id for update; if not found or v.definition_id<>d.id or v.status<>'approved' or not public.can_report('reports.publish',d.tenant_id,d.organization_id,d.facility_id) or not public.validate_report_definition(v.definition,d.module_key) then raise exception 'Report publication denied'; end if; perform set_config('app.reporting_controlled','on',true); perform set_config('app.reporting_audit','on',true); update public.report_versions set status='published',updated_at=now(),updated_by=auth.uid() where id=v.id; update public.report_definitions set status='published',current_version_id=v.id,updated_at=now(),updated_by=auth.uid() where id=d.id; perform public.append_reporting_audit_event(d.tenant_id,d.organization_id,d.facility_id,'report.published','report_definition',d.id,jsonb_build_object('versionId',v.id)); end $$;
create or replace function public.publish_dashboard(p_dashboard uuid) returns void language plpgsql security definer set search_path=public as $$ declare d public.dashboard_definitions%rowtype; begin select * into d from public.dashboard_definitions where id=p_dashboard for update; if not found or d.status<>'approved' or not public.can_report('dashboards.manage',d.tenant_id,d.organization_id,d.facility_id) or not exists(select 1 from public.dashboard_widgets where dashboard_id=d.id) then raise exception 'Dashboard publication denied'; end if; perform set_config('app.reporting_controlled','on',true); perform set_config('app.reporting_audit','on',true); update public.dashboard_definitions set status='published',updated_at=now(),updated_by=auth.uid() where id=d.id; perform public.append_reporting_audit_event(d.tenant_id,d.organization_id,d.facility_id,'dashboard.published','dashboard_definition',d.id,'{}'); end $$;
create or replace function public.request_report_export(p_run_id uuid,p_format text,p_language text) returns uuid language plpgsql security definer set search_path=public as $$ declare r public.report_runs%rowtype; id uuid; begin if p_format not in ('pdf','excel','csv') then raise exception 'Invalid report export format'; end if; if p_language not in ('ar','en','bilingual') then raise exception 'Invalid report export language'; end if; select * into r from public.report_runs where id=p_run_id and requested_by=auth.uid() for update; if not found or r.status<>'completed' or not public.can_report('reports.export',r.tenant_id,r.organization_id,r.facility_id) or (r.contains_confidential and not public.has_platform_permission('reports.export_confidential',r.tenant_id,r.organization_id,r.facility_id)) then raise exception 'Report export denied'; end if; perform set_config('app.reporting_audit','on',true); insert into public.report_exports(tenant_id,organization_id,facility_id,report_run_id,format,language,requested_by,expires_at) values(r.tenant_id,r.organization_id,r.facility_id,r.id,p_format,p_language,auth.uid(),now()+interval '24 hours') returning id into id; perform public.append_reporting_audit_event(r.tenant_id,r.organization_id,r.facility_id,'report.export_requested','report_run',r.id,jsonb_build_object('format',p_format,'language',p_language)); return id; end $$;
revoke all on function public.append_reporting_audit_event(uuid,uuid,uuid,text,text,uuid,jsonb) from public,anon,authenticated; revoke all on function public.publish_report_version(uuid,uuid),public.publish_dashboard(uuid),public.request_report_export(uuid,text,text) from public,anon; grant execute on function public.publish_report_version(uuid,uuid),public.publish_dashboard(uuid),public.request_report_export(uuid,text,text) to authenticated;
